// Domain equalities follow by transitivity through pre_self_'s domains.
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
assert(post1_self_.container_dom() =~= post2_self_.container_dom());
assert(post1_self_.endpoint_dom() =~= post2_self_.endpoint_dom());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

// Pull both per-run ensures-foralls for proc into scope with explicit
// triggers so they instantiate on our skolem ptr regardless of which
// trigger Verus' #![auto] picked.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr) implies
        post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr) by { }
assert forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    post2_self_.proc_dom().contains(p_ptr) implies
        post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr) by { }

// Pointwise: post1.get_proc(p) =~= post2.get_proc(p) on the shared domain.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr) implies
        post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr)
by {
    assert(pre_self_.proc_dom().contains(p_ptr));
    assert(post2_self_.proc_dom().contains(p_ptr));
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

// Same pattern for thread.
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr)]
    post1_self_.thread_dom().contains(t_ptr) implies
        post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr) by { }
assert forall|t_ptr: ThreadPtr|
    #![trigger post2_self_.get_thread(t_ptr)]
    post2_self_.thread_dom().contains(t_ptr) implies
        post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr) by { }

assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr), post2_self_.get_thread(t_ptr)]
    post1_self_.thread_dom().contains(t_ptr) implies
        post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr)
by {
    assert(pre_self_.thread_dom().contains(t_ptr));
    assert(post2_self_.thread_dom().contains(t_ptr));
    assert(post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
    assert(post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
}

// Same pattern for endpoint.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) implies
        post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr) by { }
assert forall|e_ptr: EndpointPtr|
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post2_self_.endpoint_dom().contains(e_ptr) implies
        post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr) by { }

assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) implies
        post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr)
by {
    assert(pre_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
    assert(post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
}

// Pull both per-run "off-target" container ensures with explicit triggers.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    post1_self_.container_dom().contains(c_ptr) && c_ptr != container_ptr implies
        post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr) by { }
assert forall|c_ptr: ContainerPtr|
    #![trigger post2_self_.get_container(c_ptr)]
    post2_self_.container_dom().contains(c_ptr) && c_ptr != container_ptr implies
        post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr) by { }

// Container case: split on whether c_ptr is the modified container.
// Off-target: both runs equal pre's container. On-target: every field is
// pinned to a function of pre + new_quota in both runs, so they coincide.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
    post1_self_.container_dom().contains(c_ptr) implies
        post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr)
by {
    assert(pre_self_.container_dom().contains(c_ptr));
    assert(post2_self_.container_dom().contains(c_ptr));
    if c_ptr != container_ptr {
        assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    } else {
        // Every field of the container at container_ptr is pinned in both runs.
        assert(post1_self_.get_container(container_ptr).owned_procs
            =~= pre_self_.get_container(container_ptr).owned_procs);
        assert(post2_self_.get_container(container_ptr).owned_procs
            =~= pre_self_.get_container(container_ptr).owned_procs);
        assert(post1_self_.get_container(container_ptr).parent
            =~= pre_self_.get_container(container_ptr).parent);
        assert(post2_self_.get_container(container_ptr).parent
            =~= pre_self_.get_container(container_ptr).parent);
        assert(post1_self_.get_container(container_ptr).parent_rev_ptr
            =~= pre_self_.get_container(container_ptr).parent_rev_ptr);
        assert(post2_self_.get_container(container_ptr).parent_rev_ptr
            =~= pre_self_.get_container(container_ptr).parent_rev_ptr);
        assert(post1_self_.get_container(container_ptr).children
            =~= pre_self_.get_container(container_ptr).children);
        assert(post2_self_.get_container(container_ptr).children
            =~= pre_self_.get_container(container_ptr).children);
        assert(post1_self_.get_container(container_ptr).owned_endpoints
            =~= pre_self_.get_container(container_ptr).owned_endpoints);
        assert(post2_self_.get_container(container_ptr).owned_endpoints
            =~= pre_self_.get_container(container_ptr).owned_endpoints);
        assert(post1_self_.get_container(container_ptr).owned_threads
            =~= pre_self_.get_container(container_ptr).owned_threads);
        assert(post2_self_.get_container(container_ptr).owned_threads
            =~= pre_self_.get_container(container_ptr).owned_threads);
        assert(post1_self_.get_container(container_ptr).owned_cpus
            =~= pre_self_.get_container(container_ptr).owned_cpus);
        assert(post2_self_.get_container(container_ptr).owned_cpus
            =~= pre_self_.get_container(container_ptr).owned_cpus);
        assert(post1_self_.get_container(container_ptr).scheduler
            =~= pre_self_.get_container(container_ptr).scheduler);
        assert(post2_self_.get_container(container_ptr).scheduler
            =~= pre_self_.get_container(container_ptr).scheduler);
        assert(post1_self_.get_container(container_ptr).depth
            =~= pre_self_.get_container(container_ptr).depth);
        assert(post2_self_.get_container(container_ptr).depth
            =~= pre_self_.get_container(container_ptr).depth);
        assert(post1_self_.get_container(container_ptr).uppertree_seq
            =~= pre_self_.get_container(container_ptr).uppertree_seq);
        assert(post2_self_.get_container(container_ptr).uppertree_seq
            =~= pre_self_.get_container(container_ptr).uppertree_seq);
        assert(post1_self_.get_container(container_ptr).subtree_set
            =~= pre_self_.get_container(container_ptr).subtree_set);
        assert(post2_self_.get_container(container_ptr).subtree_set
            =~= pre_self_.get_container(container_ptr).subtree_set);
        assert(post1_self_.get_container(container_ptr).root_process
            =~= pre_self_.get_container(container_ptr).root_process);
        assert(post2_self_.get_container(container_ptr).root_process
            =~= pre_self_.get_container(container_ptr).root_process);
        // Both runs set quota to the same expression of pre + new_quota.
        assert(post1_self_.get_container(container_ptr).quota
            =~= pre_self_.get_container(container_ptr).quota.spec_set_mem_4k(new_quota));
        assert(post2_self_.get_container(container_ptr).quota
            =~= pre_self_.get_container(container_ptr).quota.spec_set_mem_4k(new_quota));
        assert(post1_self_.get_container(container_ptr).quota
            =~= post2_self_.get_container(container_ptr).quota);
    }
}
